#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,a[10003],sum=0;
    priority_queue<int,vector<int>,greater<int> > p;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        p.push(a[i]);
    }
    while(p.size()>1){
        int x=p.top();
        p.pop();
        int y=p.top();
        p.pop();
        sum+=x+y;
        p.push(x+y);
    }
    cout<<sum;
    return 0;
}
